--
-- Структура таблицы `offers`
--

CREATE TABLE `offers` (
  `id` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  `slug` varchar(255) NOT NULL,
  `category` enum('microloans','credits','credit_cards','debit_cards') NOT NULL,
  `amount_min` int(11) NOT NULL DEFAULT 1000,
  `amount_max` int(11) NOT NULL DEFAULT 100000,
  `term_min_days` int(11) NOT NULL DEFAULT 1,
  `term_max_days` int(11) NOT NULL DEFAULT 365,
  `psk` decimal(6,2) NOT NULL DEFAULT 0.00,
  `rate` decimal(6,2) NOT NULL DEFAULT 0.00,
  `free_term_days` int(11) NOT NULL DEFAULT 0,
  `logo_url` text DEFAULT NULL,
  `affiliate_url` text NOT NULL,
  `borrower_category` enum('employed','unemployed','pensioner','student','self_employed','any') NOT NULL DEFAULT 'any',
  `description` text DEFAULT NULL,
  `seo_keywords` text DEFAULT NULL,
  `regions` text DEFAULT NULL,
  `rating` decimal(3,1) NOT NULL DEFAULT 0.0,
  `review_count` int(11) NOT NULL DEFAULT 0,
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  `sort_order` int(11) NOT NULL DEFAULT 0,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Дамп данных таблицы `offers`
--

INSERT INTO `offers` (`id`, `title`, `slug`, `category`, `amount_min`, `amount_max`, `term_min_days`, `term_max_days`, `psk`, `rate`, `free_term_days`, `logo_url`, `affiliate_url`, `borrower_category`, `description`, `seo_keywords`, `regions`, `rating`, `review_count`, `is_active`, `sort_order`, `created_at`, `updated_at`) VALUES
(1, 'Вебзайм', 'vebzaym-1784652197596', 'microloans', 3000, 100000, 7, 100, '292.00', '0.80', 14, '/images/offer/webzaim.svg', 'https://pxl.leads.su/click/7588a80882fc0991f52f502f555fad9f?source=kosmozaim&erid=2W5zFGjNpAL', 'any', 'Процентная ставка от 0% до 0,8 % в день. 0% на 1-й заем, при условии его погашения в течение 14 дней, в ином случае 0,8% в день с 1-го дня. ', '', '', '0.0', 0, 1, 3, '2026-07-21 16:43:17', '2026-07-22 06:28:38'),
(2, 'JoyMoney', 'joymoney-1784652794306', 'microloans', 3000, 30000, 10, 14, '292.00', '0.80', 14, '/images/offer/JoyMoney.svg', 'https://pxl.leads.su/click/fef2f880e5283742cfadf801cfbbe5ce?source=kosmozaim&erid=2W5zFK1Gnqv', 'any', 'Акция для новых клиентов: для займа погашенного в срок до 14 дней начисленные проценты списываются в полном объеме, от 15 дней ставка составит 0,8% в день за весь срок пользования займом.', '', '', '0.0', 0, 1, 2, '2026-07-21 16:53:14', '2026-07-22 06:28:38'),
(3, 'BunnyMoney', 'bunnymoney-1784653580212', 'microloans', 1000, 30000, 3, 31, '292.00', '0.80', 31, '/images/offer/BunnyMoney.svg', 'https://pxl.leads.su/click/bc564cf83b18c0e4770681c1ef45a19c?source=kosmozaim&erid=2W5zFHc6Gbz', 'any', 'Займ до 9 000 ₽ под 0% сроком от 10 до 31 дня для улучшению кредитного рейтинга при оформлении услуги «Кредитный рейтинг» за 1 699 ₽', 'займ онлайн, без подтверждения дохода, займ от 19 лет', '', '0.0', 0, 1, 1, '2026-07-21 17:06:20', '2026-07-22 06:28:38'),
(4, 'Webbankir', 'webbankir-1784655589265', 'microloans', 1000, 100000, 7, 180, '292.00', '0.80', 21, '/images/offer/Webbankirl.svg', 'https://pxl.leads.su/click/34d3d8b075871048e78919226f73f86b?source=kosmozaim&erid=2W5zFHrMC2D', 'any', '0% при первичном обращении для займа суммой до 30 000 ₽ и сроком до 21 дня', 'заем за несколько минут, займ онлайн, без подтверждения дохода', '', '5.0', 1, 1, 4, '2026-07-21 17:39:49', '2026-07-22 06:28:38');

