--
-- Структура таблицы `reviews`
--

CREATE TABLE `reviews` (
  `id` int(11) NOT NULL,
  `offer_id` int(11) NOT NULL,
  `author_name` varchar(100) NOT NULL,
  `rating` int(11) NOT NULL DEFAULT 5,
  `comment` text NOT NULL,
  `is_approved` tinyint(1) NOT NULL DEFAULT 0,
  `created_at` timestamp NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Дамп данных таблицы `reviews`
--

INSERT INTO `reviews` (`id`, `offer_id`, `author_name`, `rating`, `comment`, `is_approved`, `created_at`) VALUES
(2, 4, 'Светлана', 5, 'Обращаюсь в Webbankir не впервые, и каждый раз подтверждается, что сервис работает честно и без уловок. В этот раз 12 июля через приложение Банки.ру оформляла новый займ. Выбирала из списка предложений, сравнивала условия — остановилась на Webbankir. Перешла на сайт компании, применила промокод, запросила 4 000 рублей на 30 дней.\n\nВ личном кабинете сразу увидела полную сумму к возврату — без скрытых услуг, без навязанных страховок и \"онлайн-докторов\". В других МФО часто пытаются подсунуть лишнее, а то и вовсе одобрить сумму в десять раз больше заявленной, чтобы потом клиент разбирался с новыми долгами. Здесь ничего такого не было: одобрили ровно ту сумму, которую я запросила, ни рублём больше.\n\nНа момент регистрации понадобился только паспорт. Оформление занимает буквально пару минут, деньги приходят на карту максимум через 5 минут после одобрения.\n\nСайт и приложение компании работают стабильно. Действует бонусная программа и промокоды. Приятно, когда попадается компания с понятными условиями и быстрым оформлением, а не та, где потом удивляешься долгам, которых не ждал.', 1, '2026-07-22 04:20:17');

